  ('social-worker-moex-01973', 'social-worker', 'social-worker-moex-107-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '兒少福利服務中心為拓展兒少服務人數，因而增加外展服務的次數與晚間的服務時間。試問該中心調整 的比較傾向是行銷組合中的那一要項？', '["產品（product）", "促銷（promotion）", "通路（place）", "定價（price）"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "f80e8558d678", "answer_pdf_sha1": "ce4f756709e0", "source_family": "moex-gov-tw", "moex": {"exam_code": "107030", "c": "107", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "107", "exam_name": "107年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 37, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
